import { useState } from "react";
import "./App.css";

const jobs = [
  { id: 1, title: "Frontend Developer", company: "Groww", location: "Bangalore", salary: "₹10–15 LPA", type: "Full-time", domain: "Engineering", exp: "Mid", desc: "Build next-gen fintech UIs used by 5M+ users using React.", req: ["2+ years React", "CSS/Tailwind", "REST APIs"], skills: ["React", "TypeScript", "CSS"], posted: "2 days ago" },
  { id: 2, title: "UI/UX Designer", company: "Zomato", location: "Remote", salary: "₹8–12 LPA", type: "Remote", domain: "Design", exp: "Mid", desc: "Design delightful food-ordering experiences for millions of users.", req: ["Figma expert", "User research", "Prototyping"], skills: ["Figma", "Sketch", "Research"], posted: "1 day ago" },
  { id: 3, title: "Data Analyst", company: "Meesho", location: "Bangalore", salary: "₹6–10 LPA", type: "Full-time", domain: "Data", exp: "Entry", desc: "Analyze large datasets from our e-commerce platform.", req: ["SQL", "Python", "Excel"], skills: ["SQL", "Python", "Tableau"], posted: "3 days ago" },
  { id: 4, title: "Backend Engineer", company: "Razorpay", location: "Bangalore", salary: "₹18–25 LPA", type: "Full-time", domain: "Engineering", exp: "Senior", desc: "Build and scale payment infrastructure processing billions daily.", req: ["Java/Go", "Distributed systems", "SQL"], skills: ["Java", "Kafka", "AWS"], posted: "1 day ago" },
  { id: 5, title: "React Native Developer", company: "PhonePe", location: "Pune", salary: "₹12–18 LPA", type: "Full-time", domain: "Engineering", exp: "Mid", desc: "Build the PhonePe super-app used by 400M+ users.", req: ["React Native 2+ yrs", "iOS/Android basics"], skills: ["React Native", "JavaScript", "Redux"], posted: "Today" },
  { id: 6, title: "Growth Marketing Intern", company: "Zepto", location: "Mumbai", salary: "₹25k/month", type: "Internship", domain: "Marketing", exp: "Entry", desc: "Drive growth experiments across email, push, and in-app channels.", req: ["Marketing basics", "Excel", "Communication"], skills: ["Email marketing", "Analytics"], posted: "Today" },
];

const colors = [
  { bg: "#E6F1FB", text: "#185FA5" },
  { bg: "#EAF3DE", text: "#3B6D11" },
  { bg: "#EEEDFE", text: "#3C3489" },
  { bg: "#FAEEDA", text: "#854F0B" },
  { bg: "#FAECE7", text: "#993C1D" },
  { bg: "#FBEAF0", text: "#993556" },
];

function initials(name) {
  return name.split(" ").slice(0, 2).map((w) => w[0]).join("").toUpperCase();
}

export default function App() {
  const [page, setPage] = useState("browse");
  const [selectedJob, setSelectedJob] = useState(null);
  const [savedJobs, setSavedJobs] = useState([]);
  const [search, setSearch] = useState("");
  const [filterType, setFilterType] = useState("");
  const [filterExp, setFilterExp] = useState("");
  const [toast, setToast] = useState("");
  const [postForm, setPostForm] = useState({ title: "", company: "", location: "", salary: "", type: "Full-time", domain: "Engineering", desc: "" });
  const [postedJobs, setPostedJobs] = useState([]);
  const [aiSkills, setAiSkills] = useState("");
  const [aiResult, setAiResult] = useState("");
  const [aiLoading, setAiLoading] = useState(false);

  const allJobs = [...jobs, ...postedJobs];

  const filtered = allJobs.filter((j) => {
    const q = search.toLowerCase();
    const matchQ = !q || j.title.toLowerCase().includes(q) || j.company.toLowerCase().includes(q);
    const matchT = !filterType || j.type === filterType;
    const matchE = !filterExp || j.exp === filterExp;
    return matchQ && matchT && matchE;
  });

  function showToast(msg) {
    setToast(msg);
    setTimeout(() => setToast(""), 2500);
  }

  function toggleSave(job) {
    if (savedJobs.find((j) => j.id === job.id)) {
      setSavedJobs(savedJobs.filter((j) => j.id !== job.id));
      showToast("Removed from saved");
    } else {
      setSavedJobs([...savedJobs, job]);
      showToast("Job saved!");
    }
  }

  function handlePost() {
    if (!postForm.title || !postForm.company || !postForm.desc) {
      showToast("Please fill in all fields");
      return;
    }
    const newJob = { ...postForm, id: Date.now(), exp: "Mid", req: ["See description"], skills: [], posted: "Just now" };
    setPostedJobs([newJob, ...postedJobs]);
    setPostForm({ title: "", company: "", location: "", salary: "", type: "Full-time", domain: "Engineering", desc: "" });
    showToast("Job published!");
    setPage("browse");
  }

  async function runAIMatch() {
    if (!aiSkills.trim()) { showToast("Please enter your skills"); return; }
    setAiLoading(true);
    setAiResult("");
    try {
      const jobList = allJobs.map((j) => `${j.id}. ${j.title} at ${j.company} — ${j.domain}, ${j.type}, ${j.exp} level`).join("\n");
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 1000,
          system: "You are a career advisor. Given a candidate profile and job listings, recommend the top 3 best-fit jobs with a short reason for each. Be encouraging. Format: '1. Job Title at Company — reason'. Add a short tip at the end. Plain text only.",
          messages: [{ role: "user", content: `My profile:\n${aiSkills}\n\nJobs:\n${jobList}\n\nTop 3 matches?` }],
        }),
      });
      const data = await res.json();
      const text = data.content?.map((c) => c.text || "").join("") || "Could not get recommendations.";
      setAiResult(text);
    } catch {
      setAiResult("Could not connect to AI. Please try again.");
    }
    setAiLoading(false);
  }

  const styles = {
    app: { fontFamily: "system-ui, sans-serif", minHeight: "100vh", background: "#f5f5f5" },
    navbar: { background: "#fff", borderBottom: "1px solid #eee", padding: "0 1.5rem", height: 56, display: "flex", alignItems: "center", justifyContent: "space-between", position: "sticky", top: 0, zIndex: 100 },
    logo: { fontWeight: 600, fontSize: 20, color: "#185FA5", display: "flex", alignItems: "center", gap: 8 },
    dot: { width: 10, height: 10, background: "#185FA5", borderRadius: "50%" },
    navLinks: { display: "flex", gap: 4 },
    navBtn: (active) => ({ background: active ? "#E6F1FB" : "none", border: "none", padding: "6px 14px", borderRadius: 8, fontSize: 14, cursor: "pointer", color: active ? "#185FA5" : "#666", fontWeight: active ? 600 : 400 }),
    postBtn: { background: "#185FA5", color: "#fff", border: "none", borderRadius: 8, padding: "7px 16px", fontSize: 14, fontWeight: 600, cursor: "pointer" },
    hero: { background: "#fff", borderBottom: "1px solid #eee", padding: "2.5rem 1.5rem 2rem", textAlign: "center" },
    h1: { fontSize: 28, fontWeight: 600, color: "#111", marginBottom: 6 },
    sub: { color: "#666", fontSize: 15, marginBottom: "1.2rem" },
    searchRow: { display: "flex", gap: 8, maxWidth: 520, margin: "0 auto" },
    input: { flex: 1, padding: "9px 14px", border: "1px solid #ddd", borderRadius: 8, fontSize: 14, outline: "none" },
    searchBtn: { background: "#185FA5", color: "#fff", border: "none", borderRadius: 8, padding: "9px 20px", fontSize: 14, fontWeight: 600, cursor: "pointer" },
    filtersBar: { display: "flex", gap: 8, padding: "0.8rem 1.5rem", background: "#fff", borderBottom: "1px solid #eee", overflowX: "auto" },
    select: { border: "1px solid #ddd", background: "#fff", padding: "5px 10px", borderRadius: 20, fontSize: 13, cursor: "pointer" },
    chip: (active) => ({ border: `1px solid ${active ? "#85B7EB" : "#ddd"}`, background: active ? "#E6F1FB" : "#fff", padding: "5px 14px", borderRadius: 20, fontSize: 13, cursor: "pointer", color: active ? "#185FA5" : "#666" }),
    layout: { display: "flex", maxHeight: "calc(100vh - 180px)" },
    jobList: { width: 400, borderRight: "1px solid #eee", overflowY: "auto", padding: "1rem" },
    jobCard: (selected) => ({ background: "#fff", border: `${selected ? 2 : 1}px solid ${selected ? "#378ADD" : "#eee"}`, borderRadius: 12, padding: "1rem", marginBottom: 10, cursor: "pointer" }),
    cardTop: { display: "flex", alignItems: "center", gap: 10, marginBottom: 8 },
    logo2: (bg, text) => ({ width: 36, height: 36, borderRadius: 8, background: bg, color: text, display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 600, fontSize: 13, flexShrink: 0 }),
    jobTitle: { fontSize: 14, fontWeight: 600, color: "#111" },
    jobSub: { fontSize: 13, color: "#666" },
    badgeRow: { display: "flex", gap: 6, flexWrap: "wrap" },
    badge: (bg, color) => ({ fontSize: 11, padding: "3px 8px", borderRadius: 20, background: bg, color }),
    detail: { flex: 1, padding: "1.5rem", overflowY: "auto" },
    empty: { display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", height: 300, color: "#aaa", fontSize: 15 },
    detailTitle: { fontSize: 22, fontWeight: 600, color: "#111", marginBottom: 2 },
    detailSub: { fontSize: 15, color: "#666", marginBottom: "1rem" },
    metaRow: { display: "flex", gap: 16, background: "#f5f5f5", borderRadius: 8, padding: "0.8rem 1rem", marginBottom: "1rem", flexWrap: "wrap" },
    metaItem: { fontSize: 13, color: "#555" },
    applyBtn: { background: "#185FA5", color: "#fff", border: "none", borderRadius: 8, padding: "10px 24px", fontSize: 14, fontWeight: 600, cursor: "pointer" },
    saveBtn: (saved) => ({ background: saved ? "#E6F1FB" : "#fff", border: "1px solid #ddd", borderRadius: 8, padding: "10px 14px", cursor: "pointer", fontSize: 14, color: saved ? "#185FA5" : "#666" }),
    section: { marginBottom: "1.2rem" },
    sectionTitle: { fontSize: 14, fontWeight: 600, color: "#111", marginBottom: 6, borderBottom: "1px solid #eee", paddingBottom: 6 },
    skillTag: { display: "inline-block", background: "#f0f0f0", border: "1px solid #e0e0e0", borderRadius: 20, fontSize: 12, padding: "4px 10px", marginRight: 6, marginBottom: 6, color: "#555" },
    page: { maxWidth: 660, margin: "0 auto", padding: "1.5rem" },
    formLabel: { display: "block", fontSize: 13, color: "#666", marginBottom: 4 },
    formInput: { width: "100%", padding: "9px 12px", border: "1px solid #ddd", borderRadius: 8, fontSize: 14, marginBottom: "1rem", outline: "none", boxSizing: "border-box" },
    formGrid: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 },
    submitBtn: { background: "#185FA5", color: "#fff", border: "none", borderRadius: 8, padding: "12px", fontSize: 14, fontWeight: 600, cursor: "pointer", width: "100%" },
    aiBox: { background: "#fff", border: "1px solid #ddd", borderRadius: 12, padding: "1rem", marginBottom: "1rem" },
    aiBtn: { background: "#534AB7", color: "#fff", border: "none", borderRadius: 8, padding: "10px 20px", fontSize: 14, fontWeight: 600, cursor: "pointer" },
    aiResult: { background: "#fff", border: "1px solid #ddd", borderRadius: 12, padding: "1.2rem", marginTop: "1rem" },
    toast: { position: "fixed", bottom: "1.5rem", right: "1.5rem", background: "#185FA5", color: "#fff", padding: "10px 18px", borderRadius: 8, fontSize: 14, zIndex: 999, display: toast ? "block" : "none" },
  };

  return (
    <div style={styles.app}>
      {/* Navbar */}
      <nav style={styles.navbar}>
        <div style={styles.logo}><div style={styles.dot}></div> JobHub</div>
        <div style={styles.navLinks}>
          <button style={styles.navBtn(page === "browse")} onClick={() => setPage("browse")}>Browse Jobs</button>
          <button style={styles.navBtn(page === "ai")} onClick={() => setPage("ai")}>AI Match</button>
          <button style={styles.navBtn(page === "saved")} onClick={() => setPage("saved")}>Saved ({savedJobs.length})</button>
        </div>
        <button style={styles.postBtn} onClick={() => setPage("post")}>+ Post a Job</button>
      </nav>

      {/* Browse Page */}
      {page === "browse" && (
        <>
          <div style={styles.hero}>
            <h1 style={styles.h1}>Find your next opportunity</h1>
            <p style={styles.sub}>Thousands of jobs from top companies</p>
            <div style={styles.searchRow}>
              <input style={styles.input} placeholder="Job title or company..." value={search} onChange={(e) => setSearch(e.target.value)} onKeyDown={(e) => e.key === "Enter" && setSearch(e.target.value)} />
              <button style={styles.searchBtn}>Search</button>
            </div>
          </div>
          <div style={styles.filtersBar}>
            <select style={styles.select} value={filterType} onChange={(e) => setFilterType(e.target.value)}>
              <option value="">All types</option>
              <option>Full-time</option>
              <option>Remote</option>
              <option>Internship</option>
            </select>
            {["", "Entry", "Mid", "Senior"].map((exp) => (
              <button key={exp} style={styles.chip(filterExp === exp)} onClick={() => setFilterExp(exp)}>
                {exp || "All levels"}
              </button>
            ))}
          </div>
          <div style={styles.layout}>
            <div style={styles.jobList}>
              {filtered.length === 0 && <p style={{ color: "#aaa", textAlign: "center", marginTop: "2rem" }}>No jobs found</p>}
              {filtered.map((job, i) => {
                const c = colors[i % colors.length];
                const saved = !!savedJobs.find((j) => j.id === job.id);
                return (
                  <div key={job.id} style={styles.jobCard(selectedJob?.id === job.id)} onClick={() => setSelectedJob(job)}>
                    <div style={styles.cardTop}>
                      <div style={styles.logo2(c.bg, c.text)}>{initials(job.company)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={styles.jobTitle}>{job.title}</div>
                        <div style={styles.jobSub}>{job.company} · {job.location}</div>
                      </div>
                      <button onClick={(e) => { e.stopPropagation(); toggleSave(job); }} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 18, color: saved ? "#185FA5" : "#ccc" }}>
                        {saved ? "★" : "☆"}
                      </button>
                    </div>
                    <div style={styles.badgeRow}>
                      <span style={styles.badge("#E6F1FB", "#185FA5")}>{job.type}</span>
                      <span style={styles.badge("#f0f0f0", "#555")}>{job.domain}</span>
                      <span style={styles.badge("#EAF3DE", "#3B6D11")}>{job.exp}</span>
                      <span style={styles.badge("#f0f0f0", "#555")}>{job.salary}</span>
                    </div>
                  </div>
                );
              })}
            </div>
            <div style={styles.detail}>
              {!selectedJob ? (
                <div style={styles.empty}>
                  <span style={{ fontSize: 40 }}>💼</span>
                  <p>Select a job to see details</p>
                </div>
              ) : (
                <>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "1rem" }}>
                    <div>
                      <div style={styles.detailTitle}>{selectedJob.title}</div>
                      <div style={styles.detailSub}>{selectedJob.company} · {selectedJob.location} · Posted {selectedJob.posted}</div>
                    </div>
                    <div style={{ display: "flex", gap: 8 }}>
                      <button style={styles.saveBtn(!!savedJobs.find((j) => j.id === selectedJob.id))} onClick={() => toggleSave(selectedJob)}>
                        {savedJobs.find((j) => j.id === selectedJob.id) ? "★ Saved" : "☆ Save"}
                      </button>
                      <button style={styles.applyBtn} onClick={() => showToast("Application submitted! ✅")}>Apply Now</button>
                    </div>
                  </div>
                  <div style={styles.metaRow}>
                    <span style={styles.metaItem}>📍 {selectedJob.location}</span>
                    <span style={styles.metaItem}>⏰ {selectedJob.type}</span>
                    <span style={styles.metaItem}>💰 {selectedJob.salary}</span>
                    <span style={styles.metaItem}>📈 {selectedJob.exp} level</span>
                  </div>
                  <div style={styles.section}>
                    <div style={styles.sectionTitle}>About the role</div>
                    <p style={{ fontSize: 14, color: "#555", lineHeight: 1.7 }}>{selectedJob.desc}</p>
                  </div>
                  <div style={styles.section}>
                    <div style={styles.sectionTitle}>Requirements</div>
                    <ul style={{ paddingLeft: "1.2rem" }}>
                      {selectedJob.req.map((r, i) => <li key={i} style={{ fontSize: 14, color: "#555", lineHeight: 1.8 }}>{r}</li>)}
                    </ul>
                  </div>
                  <div style={styles.section}>
                    <div style={styles.sectionTitle}>Skills</div>
                    <div>{selectedJob.skills.map((s) => <span key={s} style={styles.skillTag}>{s}</span>)}</div>
                  </div>
                </>
              )}
            </div>
          </div>
        </>
      )}

      {/* AI Match Page */}
      {page === "ai" && (
        <div style={styles.page}>
          <h2 style={{ fontSize: 22, fontWeight: 600, marginBottom: 6 }}>AI Job Matching</h2>
          <p style={{ color: "#666", fontSize: 14, marginBottom: "1.2rem" }}>Paste your skills and get personalized job recommendations powered by AI.</p>
          <div style={styles.aiBox}>
            <textarea style={{ width: "100%", border: "none", outline: "none", fontSize: 14, lineHeight: 1.6, resize: "vertical", minHeight: 80, background: "transparent", fontFamily: "system-ui" }}
              placeholder="e.g. I know JavaScript, React, CSS. I have 1 year experience building web apps..."
              value={aiSkills} onChange={(e) => setAiSkills(e.target.value)} />
          </div>
          <button style={styles.aiBtn} onClick={runAIMatch} disabled={aiLoading}>
            {aiLoading ? "Matching..." : "✨ Match me to jobs"}
          </button>
          {aiResult && (
            <div style={styles.aiResult}>
              <h3 style={{ fontSize: 15, fontWeight: 600, marginBottom: "0.75rem" }}>✨ Your top matches</h3>
              <p style={{ fontSize: 14, color: "#555", lineHeight: 1.8, whiteSpace: "pre-wrap" }}>{aiResult}</p>
            </div>
          )}
        </div>
      )}

      {/* Saved Page */}
      {page === "saved" && (
        <div style={styles.page}>
          <h2 style={{ fontSize: 22, fontWeight: 600, marginBottom: "1.2rem" }}>Saved Jobs</h2>
          {savedJobs.length === 0 ? (
            <div style={styles.empty}><span style={{ fontSize: 40 }}>🔖</span><p>No saved jobs yet</p></div>
          ) : (
            savedJobs.map((job, i) => {
              const c = colors[i % colors.length];
              return (
                <div key={job.id} style={styles.jobCard(false)} onClick={() => { setSelectedJob(job); setPage("browse"); }}>
                  <div style={styles.cardTop}>
                    <div style={styles.logo2(c.bg, c.text)}>{initials(job.company)}</div>
                    <div>
                      <div style={styles.jobTitle}>{job.title}</div>
                      <div style={styles.jobSub}>{job.company} · {job.location}</div>
                    </div>
                  </div>
                  <div style={styles.badgeRow}>
                    <span style={styles.badge("#E6F1FB", "#185FA5")}>{job.type}</span>
                    <span style={styles.badge("#f0f0f0", "#555")}>{job.salary}</span>
                  </div>
                </div>
              );
            })
          )}
        </div>
      )}

      {/* Post a Job Page */}
      {page === "post" && (
        <div style={styles.page}>
          <h2 style={{ fontSize: 22, fontWeight: 600, marginBottom: "1.2rem" }}>Post a Job</h2>
          <div style={styles.formGrid}>
            <div>
              <label style={styles.formLabel}>Job title</label>
              <input style={styles.formInput} placeholder="e.g. Frontend Developer" value={postForm.title} onChange={(e) => setPostForm({ ...postForm, title: e.target.value })} />
            </div>
            <div>
              <label style={styles.formLabel}>Company name</label>
              <input style={styles.formInput} placeholder="e.g. Acme Corp" value={postForm.company} onChange={(e) => setPostForm({ ...postForm, company: e.target.value })} />
            </div>
          </div>
          <div style={styles.formGrid}>
            <div>
              <label style={styles.formLabel}>Location</label>
              <input style={styles.formInput} placeholder="e.g. Mumbai / Remote" value={postForm.location} onChange={(e) => setPostForm({ ...postForm, location: e.target.value })} />
            </div>
            <div>
              <label style={styles.formLabel}>Salary</label>
              <input style={styles.formInput} placeholder="e.g. ₹8–12 LPA" value={postForm.salary} onChange={(e) => setPostForm({ ...postForm, salary: e.target.value })} />
            </div>
          </div>
          <div style={styles.formGrid}>
            <div>
              <label style={styles.formLabel}>Job type</label>
              <select style={styles.formInput} value={postForm.type} onChange={(e) => setPostForm({ ...postForm, type: e.target.value })}>
                <option>Full-time</option>
                <option>Part-time</option>
                <option>Remote</option>
                <option>Internship</option>
              </select>
            </div>
            <div>
              <label style={styles.formLabel}>Domain</label>
              <select style={styles.formInput} value={postForm.domain} onChange={(e) => setPostForm({ ...postForm, domain: e.target.value })}>
                <option>Engineering</option>
                <option>Design</option>
                <option>Marketing</option>
                <option>Data</option>
                <option>Product</option>
              </select>
            </div>
          </div>
          <label style={styles.formLabel}>Job description</label>
          <textarea style={{ ...styles.formInput, minHeight: 100, resize: "vertical" }} placeholder="Describe the role..." value={postForm.desc} onChange={(e) => setPostForm({ ...postForm, desc: e.target.value })} />
          <button style={styles.submitBtn} onClick={handlePost}>Publish Job Listing</button>
        </div>
      )}

      {/* Toast */}
      <div style={styles.toast}>{toast}</div>
    </div>
  );
}
